import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import org.owasp.esapi.ESAPI;

public class XSSSecureCode {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly escape user input using ESAPI encoder
        String escapedUserInput = ESAPI.encoder().encodeForHTML(userInput);

        String output = "<p>" + escapedUserInput + "</p>";

        File file = new File("output.html");
        try (FileWriter writer = new FileWriter(file)) {
            writer.write(output);
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
